#!/usr/bin/env bash
# Usage: ./scripts/qa/run-bench.sh [WORKSPACE_DIR]
# Runs --dump-package on the QA workspace twice with PERL_LSP_BENCH=1.
# First run resolves @INC; second run reads from SQLite cache.
# Requires release build (`cargo build --release`) and a workspace
# generated by gen-workspace.sh.
#
# Output: WORKSPACE_DIR/bench-1.log, WORKSPACE_DIR/bench-2.log
set -euo pipefail

WS="${1:-qa-workspace}"
BIN="./target/release/perl-lsp"

[ -x "$BIN" ] || { echo "missing $BIN — run 'cargo build --release'"; exit 1; }
[ -f "$WS/lib/QA.pm" ] || { echo "missing $WS/lib/QA.pm — run gen-workspace.sh first"; exit 1; }

for run in 1 2; do
  out="$WS/bench-$run.log"
  echo ">>> run $run -> $out"
  PERL_LSP_BENCH=1 /usr/bin/time -p "$BIN" --dump-package "$WS" QA \
    > /dev/null 2> "$out"
  bench_lines=$(grep -c "^bench" "$out" || true)
  summary=$(grep -E "^(Cache:|Modules:|real |user |sys )" "$out" | tr '\n' ' ')
  echo "  bench events: $bench_lines"
  echo "  $summary"
done
